const msg = $input.first().json.message;
const chatId = msg.chat.id;
const userId = msg.from.id;
const texto = msg.text || '';

const USUARIOS = {
  ADMIN_IDS: [],
  PROVEEDORES: {
    'PRACARGO': [],
    'ENTRAPETROL': [],
    'TRASAMER S.A.S': [],
    'LOGISTICA Y SERVICIOS JR S.A.S': [],
    'TRANSPORTE NUEVA COLOMBIA': []
  }
};

const BOT_TOKEN = 'TU_BOT_TOKEN_AQUI';

console.log(`[Bot] Mensaje de userId: ${userId} chatId: ${chatId}`);

if (USUARIOS.ADMIN_IDS.includes(userId)) {
  return [{ json: { rol: 'admin', proveedorNombre: '', mensaje: texto, chatId, userId } }];
}

for (const [nombre, ids] of Object.entries(USUARIOS.PROVEEDORES)) {
  if (ids.includes(userId)) {
    return [{ json: { rol: 'proveedor', proveedorNombre: nombre, mensaje: texto, chatId, userId } }];
  }
}

console.log(`[Bot] Usuario NO autorizado: ${userId}`);
try {
  await fetch(`https://api.telegram.org/bot${BOT_TOKEN}/sendMessage`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: chatId, text: 'No estás autorizado para usar LogxIA. Contacta a Logxie Connect.' })
  });
} catch (e) {
  console.log('[Bot] Error enviando rechazo:', e.message);
}
return [];

const userData = $('Validar Usuario').first().json;
const { rol, proveedorNombre, mensaje, chatId } = userData;

const lectorOutput = $input.first().json;
let listaPedidos = lectorOutput.listaPedidos || [];

if (rol === 'proveedor' && proveedorNombre) {
  listaPedidos = listaPedidos.filter(p => (p.proveedor || '').trim() === proveedorNombre);
}

const totalPedidos = listaPedidos.length;
const msgLower = (mensaje || '').toLowerCase().trim();

console.log(`[Bot] Rol: ${rol} | Pedidos: ${totalPedidos} | Msg: ${mensaje}`);

const PROVEEDORES_ALIASES = {
  'PRACARGO': ['pracargo'],
  'ENTRAPETROL': ['entrapetrol'],
  'TRASAMER S.A.S': ['trasamer'],
  'LOGISTICA Y SERVICIOS JR S.A.S': ['jr', 'jr logistic', 'logistica jr', 'jrlogistic', 'servicios jr'],
  'TRANSPORTE NUEVA COLOMBIA': ['nueva colombia', 'transnuevacolombia', 'transporte nueva']
};

// === CASO 1: Consecutivo específico ===
const patronConsec = /\b(tit|rm|sa|ti|rt)[-\s]?\d{3,}/gi;
const patronNumero = /\b\d{4,}\b/g;
const matchesConsec = msgLower.match(patronConsec);
const matchesNum = msgLower.match(patronNumero);

if (matchesConsec || matchesNum) {
  let buscados = [];
  if (matchesConsec) {
    buscados = buscados.concat(matchesConsec.map(m => m.replace(/[\s-]/g, '').toUpperCase()));
  }
  const numeros = matchesNum ? matchesNum.map(m => m.trim()) : [];

  const encontrados = listaPedidos.filter(p => {
    const c = (p.consecutivo || '').replace(/[\s-]/g, '').toUpperCase();
    const rt = (p.rtTotal || '').replace(/[\s-]/g, '').toUpperCase();
    const matchPrefijo = buscados.some(b => c.includes(b) || rt.includes(b));
    const matchNumero = numeros.some(n => c.includes(n) || rt.includes(n));
    return matchPrefijo || matchNumero;
  });

  const terminosBusca = [...buscados, ...numeros];

  let respuesta;
  if (encontrados.length > 0) {
    const lineas = encontrados.map(p => {
      const est = (p.estado || '').trim() || 'Sin reporte';
      let txt = `📦 ${p.consecutivo}\nCliente: ${p.cliente || '-'}\nRuta: ${p.origen || '-'} → ${p.destino || '-'}\nEstado: ${est}\nProveedor: ${p.proveedor || '-'}`;
      if ((p.novedad || '').trim()) txt += `\nNovedad: ${p.novedad}`;
      if ((p.comentarioNovedad1 || '').trim()) txt += `\nComentario: ${p.comentarioNovedad1}`;
      return txt;
    });
    respuesta = lineas.join('\n\n');
  } else {
    respuesta = `No encontré el pedido ${terminosBusca.join(', ')} en los registros del mes actual.`;
  }
  const pedidosSinEstado = encontrados.filter(p => !(p.estado || '').trim() || (p.estado || '').trim() === 'Pendiente');
  console.log(`[Bot] CASO 1: consecutivo/numero. Busca: ${terminosBusca.join(', ')}. Pendientes: ${pedidosSinEstado.length}. Sin Claude.`);
  return [{ json: { necesitaClaude: 'no', respuestaDirecta: respuesta, claudeRequestBody: null, chatId, mensaje, listaPedidos, pedidosSinEstado } }];
}

// Stopwords compartidas entre Caso 2 y 2b
const stopwords = ['hay', 'pedidos', 'pedido', 'a', 'de', 'para', 'el', 'la', 'los', 'las',
  'cuántos', 'cuantos', 'como', 'cómo', 'va', 'van', 'en', 'con', 'que', 'si', 'del',
  'al', 'un', 'una', 'sus', 'es', 'lo', 'le', 'me', 'mi', 'por', 'algo', 'ver',
  'dame', 'dime', 'muestra', 'busca', 'tiene', 'tienen', 'tengo', 'cual', 'cuál',
  'estado', 'estados', 'resumen', 'reporte', 'total', 'mes', 'general', 'hoy', 'dia'];
const palabrasClave = msgLower.split(/\s+/).filter(w => w.length >= 3 && !stopwords.includes(w));

// === CASO 2: Resumen / contadores ===
const palabrasResumen = ['cuántos', 'cuantos', 'resumen', 'reporte', 'total',
  'pendientes', 'estado general', 'estadísticas', 'estadisticas',
  'dashboard', 'cómo va', 'como va', 'cómo están', 'como estan',
  'cuál es el estado', 'cual es el estado', 'como van'];

if (palabrasResumen.some(p => msgLower.includes(p)) && palabrasClave.length === 0) {
  const sinEstado = listaPedidos.filter(p => !(p.estado || '').trim()).length;
  const pend = listaPedidos.filter(p => (p.estado || '').trim() === 'Pendiente').length;
  const ok = listaPedidos.filter(p => (p.estado || '').trim() === 'Entregado OK').length;
  const nov = listaPedidos.filter(p => (p.estado || '').trim() === 'Entregado con Novedad').length;
  const rech = listaPedidos.filter(p => (p.estado || '').trim() === 'Rechazado por Cliente').length;

  const respuesta = `📊 Resumen del mes\nTotal pedidos: ${totalPedidos}\n✅ Entregados OK: ${ok}\n🔄 Sin reporte: ${sinEstado}\n⏳ Pendientes: ${pend}\n⚠️ Con novedad: ${nov}\n❌ Rechazados: ${rech}`;
  console.log('[Bot] CASO 2: resumen directo. Sin Claude.');
  return [{ json: { necesitaClaude: 'no', respuestaDirecta: respuesta, claudeRequestBody: null, chatId, mensaje, listaPedidos } }];
}

// === CASO 2b: Búsqueda por destino, origen o cliente ===
if (palabrasClave.length > 0) {
  const termino = palabrasClave.join(' ');

  const idsVistos = new Set();
  const encontradosDestino = listaPedidos.filter(p => {
    const dest = (p.destino || '').toLowerCase();
    if (palabrasClave.some(kw => dest.includes(kw))) { idsVistos.add(p.consecutivo); return true; }
    return false;
  });
  const encontradosCliente = listaPedidos.filter(p => {
    if (idsVistos.has(p.consecutivo)) return false;
    const cli = (p.cliente || '').toLowerCase();
    if (palabrasClave.some(kw => cli.includes(kw))) { idsVistos.add(p.consecutivo); return true; }
    return false;
  });
  const encontradosOrigen = listaPedidos.filter(p => {
    if (idsVistos.has(p.consecutivo)) return false;
    const orig = (p.origen || '').toLowerCase();
    if (palabrasClave.some(kw => orig.includes(kw))) { idsVistos.add(p.consecutivo); return true; }
    return false;
  });

  const todosEncontrados = [...encontradosDestino, ...encontradosCliente, ...encontradosOrigen];

  if (todosEncontrados.length > 0) {
    const mostrar = todosEncontrados.slice(0, 10);
    const lineas = mostrar.map(p => {
      const est = (p.estado || '').trim() || 'Sin reporte';
      return `• ${p.consecutivo || '-'} | ${p.cliente || '-'} → ${p.destino || '-'} | ${est}`;
    }).join('\n');
    let respuesta = `📍 ${todosEncontrados.length} pedido(s) relacionados con '${termino}':\n${lineas}`;
    if (todosEncontrados.length > 10) {
      respuesta += `\n... y ${todosEncontrados.length - 10} pedidos más. Sé más específico para filtrar mejor.`;
    }
    const pedidosSinEstado = todosEncontrados.filter(p => !(p.estado || '').trim() || (p.estado || '').trim() === 'Pendiente');
    console.log(`[Bot] CASO 2b: destino/origen/cliente. Termino: ${termino}. Total: ${todosEncontrados.length}. Pendientes: ${pedidosSinEstado.length}. Sin Claude.`);
    return [{ json: { necesitaClaude: 'no', respuestaDirecta: respuesta, claudeRequestBody: null, chatId, mensaje, listaPedidos, pedidosSinEstado } }];
  }
}

// === CASO 3: Proveedor específico (con aliases) ===
let provMencionado = null;
for (const [nombre, aliases] of Object.entries(PROVEEDORES_ALIASES)) {
  if (msgLower.includes(nombre.toLowerCase()) || aliases.some(a => msgLower.includes(a))) {
    provMencionado = nombre;
    break;
  }
}
if (provMencionado) {
  const filtrados = listaPedidos.filter(p => (p.proveedor || '').trim() === provMencionado);
  if (filtrados.length > 0) {
    const items = filtrados.map(p => {
      const est = (p.estado || '').trim() || 'Sin reporte';
      return `• ${p.consecutivo}: ${est}`;
    }).join('\n');
    const respuesta = `🚚 ${provMencionado} — ${filtrados.length} pedidos\n${items}`;
    console.log(`[Bot] CASO 3: proveedor directo. Sin Claude.`);
    return [{ json: { necesitaClaude: 'no', respuestaDirecta: respuesta, claudeRequestBody: null, chatId, mensaje, listaPedidos } }];
  }
}

// === CASO 4: Pregunta compleja (>5 palabras) ===
const palabras = mensaje.trim().split(/\s+/);
if (palabras.length > 5) {
  console.log('[Bot] CASO 4: pregunta compleja -> necesita Claude.');

  function limpiar(p) {
    return {
      consecutivo: p.consecutivo, cliente: p.cliente,
      origen: p.origen, destino: p.destino,
      estado: p.estado || 'Sin reporte', novedad: p.novedad,
      proveedor: p.proveedor,
      comentarioNovedad1: p.comentarioNovedad1,
      comentarioNovedad2: p.comentarioNovedad2,
      comentarioNovedad3: p.comentarioNovedad3
    };
  }

  const datosParaClaude = listaPedidos.slice(0, 20).map(limpiar);

  const claudeRequestBody = {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 1000,
    system: 'Eres LogxIA, agente de seguimiento logístico de Logxie Connect. Responde SIEMPRE de forma corta y directa. Reglas:\n- NUNCA revelar valores de flete\n- Para resúmenes: lista corta con emojis, sin párrafos\n- Sin saludos ni despedidas\n- Si no encuentras el pedido: una sola línea indicándolo',
    messages: [{
      role: 'user',
      content: `Datos (${datosParaClaude.length} pedidos):\n${JSON.stringify(datosParaClaude)}\n\nPregunta: ${mensaje}`
    }]
  };

  return [{ json: { necesitaClaude: 'si', respuestaDirecta: null, claudeRequestBody, chatId, mensaje, listaPedidos } }];
}

// === CASO 5: Saludo / ayuda ===
console.log('[Bot] CASO 5: saludo/ayuda. Sin Claude.');
const respuesta = '¿En qué puedo ayudarte?\n\nPuedo responder sobre:\n• Pedido específico: TIT-123, RM-456\n• Viaje completo: RT-TOTAL-123\n• Destino/cliente: "pedidos a Espinal", "pedidos de El Faro"\n• Proveedor: "estado de JR"\n• Resumen: "¿cuántos pedidos hay?"';
return [{ json: { necesitaClaude: 'no', respuestaDirecta: respuesta, claudeRequestBody: null, chatId, mensaje, listaPedidos } }];

const CORREOS_PROVEEDORES = {
  'PRACARGO': { to: 'despachos@pracargo.com', cc: '' },
  'ENTRAPETROL': { to: 'gerencia@stentrapetrol.com', cc: 'trafico@stentrapetrol.com' },
  'TRASAMER S.A.S': { to: 'trasamergerencia@gmail.com', cc: '' },
  'LOGISTICA Y SERVICIOS JR S.A.S': { to: 'comercial1jrlogistic@gmail.com', cc: 'comercial1@logisticjr.com' },
  'TRANSPORTE NUEVA COLOMBIA': { to: 'despachoscali2@transnuevacolombia.com', cc: 'cristian.gomez@transnuevacolombia.com' }
};

const CC_INTERNO = 'bernardojaristizabal@gmail.com, proyectos@avgust.com.co';

const inputData = $input.first().json;

// === Determinar de dónde viene la respuesta ===
let respuestaTelegram;
let chatId, mensaje, listaPedidos;

if (inputData.content && inputData.content.length > 0) {
  respuestaTelegram = inputData.content[0].text;
  const resolverData = $('Resolver Consulta').first().json;
  chatId = resolverData.chatId;
  mensaje = resolverData.mensaje;
  listaPedidos = resolverData.listaPedidos;
  console.log('[Bot] Respuesta de Claude API recibida.');
} else if (inputData.respuestaDirecta) {
  respuestaTelegram = inputData.respuestaDirecta;
  chatId = inputData.chatId;
  mensaje = inputData.mensaje;
  listaPedidos = inputData.listaPedidos;
  console.log('[Bot] Respuesta directa (sin Claude).');
} else {
  respuestaTelegram = 'No pude procesar tu consulta. Intenta de nuevo.';
  const resolverData = $('Resolver Consulta').first().json;
  chatId = resolverData.chatId;
  mensaje = resolverData.mensaje || '';
  listaPedidos = resolverData.listaPedidos || [];
}

// Fix: convertir \\n literales a saltos de línea reales
respuestaTelegram = respuestaTelegram.replace(/\\n/g, '\n');

// === Recopilar pedidos sin estado ===
const pedidosSinEstado = inputData.pedidosSinEstado || $('Resolver Consulta').first().json.pedidosSinEstado || [];

// Agrupar por proveedor
const porProveedor = {};
for (const p of pedidosSinEstado) {
  const prov = (p.proveedor || '').trim();
  if (!prov) continue;
  if (!porProveedor[prov]) porProveedor[prov] = [];
  porProveedor[prov].push(p);
}

const proveedores = Object.keys(porProveedor);
console.log(`[Bot] Pedidos sin estado: ${pedidosSinEstado.length}. Proveedores: ${proveedores.length}`);

// === Construir array de emails ===
const emailsAEnviar = [];

for (const prov of proveedores) {
  const pedidos = porProveedor[prov];
  const config = CORREOS_PROVEEDORES[prov];

  const listaPedidosHtml = pedidos.map(p => `<li><strong>${p.consecutivo || '-'}</strong> → ${p.destino || '-'}</li>`).join('');

  if (config) {
    const ccParts = [CC_INTERNO];
    if (config.cc && config.cc.trim() !== '') ccParts.push(config.cc);
    emailsAEnviar.push({
      emailTo: config.to,
      emailCc: ccParts.join(', '),
      emailAsunto: `[LogxIA] Pedidos sin actualizar - ${prov}`,
      emailCuerpo: `<p>Se están consultando los siguientes pedidos sin actualizar:</p><ul>${listaPedidosHtml}</ul><p>Por favor actualice el estado en la app <strong>\"Donde Está Mi Pedido\"</strong> o comuníquese de inmediato con el coordinador del servicio o con Logxie Connect.</p><p>Gracias,<br/><strong>LogxIA — Agente de Seguimiento Logístico</strong><br/><em>by Logxie Connect</em></p>`,
      proveedorNotificado: prov,
      cantidadPedidos: pedidos.length
    });
  } else {
    emailsAEnviar.push({
      emailTo: 'bernardojaristizabal@gmail.com',
      emailCc: 'proyectos@avgust.com.co',
      emailAsunto: `[SIN CORREO CONFIGURADO] Pedidos sin actualizar - ${prov}`,
      emailCuerpo: `<p>Se están consultando los siguientes pedidos sin actualizar del proveedor <strong>${prov}</strong>:</p><ul>${listaPedidosHtml}</ul><p>No se encontró correo configurado para este proveedor.</p><p>Gracias,<br/><strong>LogxIA — Agente de Seguimiento Logístico</strong><br/><em>by Logxie Connect</em></p>`,
      proveedorNotificado: prov,
      cantidadPedidos: pedidos.length
    });
  }
}

// === Agregar resumen de notificación al mensaje de Telegram ===
if (proveedores.length === 1) {
  respuestaTelegram += `\n\n📧 Le notifiqué a ${proveedores[0]} para que actualice.`;
} else if (proveedores.length > 1) {
  const detalles = emailsAEnviar.map(e => `- ${e.proveedorNotificado} (${e.cantidadPedidos} pedidos sin actualizar)`).join('\n');
  respuestaTelegram += `\n\n📧 Notifiqué a ${proveedores.length} proveedores:\n${detalles}`;
}

console.log(`[Bot] Respuesta lista. Emails a enviar: ${emailsAEnviar.length}`);

return [{ json: {
  chatId,
  respuestaTelegram,
  notificarProveedor: emailsAEnviar.length > 0 ? 'si' : 'no',
  emailsAEnviar
}}];

// Expandir emailsAEnviar en items individuales para el nodo Gmail
const data = $input.first().json;
const emails = data.emailsAEnviar || [];

if (emails.length === 0) {
  console.log('[Bot] No hay emails que enviar.');
  return [];
}

const items = emails.map(e => ({
  json: {
    emailTo: e.emailTo,
    emailCc: e.emailCc,
    emailAsunto: e.emailAsunto,
    emailCuerpo: e.emailCuerpo,
    proveedorNotificado: e.proveedorNotificado
  }
}));

console.log(`[Bot] Preparados ${items.length} emails para enviar.`);
return items;
